mapper.select:
SELECT * FROM (SELECT ST.SCHEDULE_GROUP_ID, S.SCHEDULE_ID AS SCHEDULE_ID, IFNULL(SG.SCHEDULE_GROUP_NAME, 'Recon Scan') AS SCHEDULE_GROUP_NAME,T.NAME, L.DESCRIPTION , CASE WHEN (SL.STATUS IN ('notscanned','queued','error','interrupted')) THEN S.SCHEDULE_STATUS ELSE SL.STATUS END AS STATUS ,DATE_FORMAT(FROM_UNIXTIME(S.SCHEDULE_NEXT_SCAN), '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(FROM_UNIXTIME(SL.started), '%Y-%m-%d %H:%i:%s') AS START_TIME , DATE_FORMAT(FROM_UNIXTIME(SL.updated), '%Y-%m-%d %H:%i:%s') AS END_TIME ,ST.POLICY_ID, SL.TARGET_ID, SL.AP_NO
,IFNULL(JSON_EXTRACT(PT.PATTERN_DATA, CONCAT(REPLACE(JSON_SEARCH(JSON_EXTRACT(PT.PATTERN_DATA, '$[*].PATTERN_NUM'),'one', #{cnt}), '"', ''), '.MATCH_CNT')), 0) AS TYPE#{cnt}
,PT.PATH_CNT , PT.TOTAL FROM (SELECT *,DATE(FROM_UNIXTIME(SCHEDULE_NEXT_SCAN)) FROM pi_schedules WHERE 1=1
AND FROM_UNIXTIME(SCHEDULE_NEXT_SCAN) BETWEEN CONCAT(#{fromDate},' 00:00:00') AND CONCAT(#{toDate},' 23:59:59')
) S JOIN (SELECT *,MAX(UPDATED) FROM pi_scheduled_location GROUP BY TARGET_ID,AP_NO,DATE(FROM_UNIXTIME(UPDATED))) SL ON SL.sch_id = S.SCHEDULE_ID AND SL.AP_NO = S.AP_NO LEFT OUTER JOIN pi_targets T ON T.target_id = SL.TARGET_ID AND T.AP_NO = SL.AP_NO LEFT OUTER JOIN pi_locations L ON SL.TARGET_ID = L.TARGET_ID AND SL.AP_NO = L.AP_NO AND SL.location_id = L.location_id LEFT OUTER JOIN pi_schedule_targets ST ON ST.recon_schedule_id = S.SCHEDULE_ID LEFT OUTER JOIN pi_schedule_group SG ON SG.schedule_group_id = ST.schedule_group_id LEFT OUTER JOIN pi_TOTAL PT ON DATE(PT.regdate) = DATE(DATE_ADD(FROM_UNIXTIME(SL.updated),INTERVAL 1 DAY)) AND SL.TARGET_ID = PT.TARGET_ID AND SL.AP_NO= PT.AP_NO
JOIN pi_target_user TU ON TU.target_id = SL.TARGET_ID AND TU.AP_NO = SL.AP_NO AND TU.USER_NO = #{user_no}
) D
WHERE 1=1
AND D.STATUS = #{status_flag}
AND D.DESCRIPTION LIKE CONCAT ('%',#{path},'%')
AND D.SCHEDULE_GROUP_NAME LIKE CONCAT ('%',#{title},'%')
AND D.NAME LIKE CONCAT ('%',#{host},'%')
ORDER BY D.PATH_CNT DESC

SELECT ST.TARGET_ID, ST.AP_NO, T.NAME AS FULL_NAME, SUBSTRING_INDEX(T.NAME, '.', 1) AS HOST_NAME, SUBSTRING_INDEX(SUBSTRING_INDEX(T.NAME, '.', -2), '.', 1) AS NAME, SUBSTRING_INDEX(T.NAME, '.', -1) AS SERIAL, T.PLATFORM, ST.RECON_SCHEDULE_ID, ST.POLICY_ID, ST.DATATYPE_ID, DU.DATATYPE_LABEL, DU.ENABLE, S.SCHEDULE_STATUS, DATE_FORMAT(ST.REGDATE, '%Y-%m-%d %H:%i:%S') AS REGDATE FROM pi_schedule_targets ST LEFT OUTER JOIN pi_datatypes_user DU ON ST.DATATYPE_ID = DU.DATATYPE_ID LEFT OUTER JOIN pi_locations L ON L.TARGET_ID = ST.TARGET_ID AND ST.LOCATION_ID = L.LOCATION_ID , pi_schedules S, pi_targets T
LEFT OUTER JOIN pi_target_user TU ON T.target_id = TU.TARGET_ID AND TU.AP_NO = T.AP_NO
WHERE 1 = 1
AND TU.USER_NO = #{user_no}
AND ST.RECON_SCHEDULE_ID = S.SCHEDULE_ID AND ST.AP_NO = S.AP_NO AND ST.TARGET_ID = T.TARGET_ID AND ST.AP_NO = T.AP_NO AND ST.SCHEDULE_GROUP_ID = #{group_id}
AND S.SCHEDULE_STATUS IN (
#{item}
)
GROUP BY T.TARGET_ID, T.AP_NO, ST.RECON_SCHEDULE_ID ORDER BY T.NAME

