SELECT H.AP_NO, H.TARGET_ID, H.LOCATION_ID, H.NAME, H.NET_ID, H.SCHEDULE_ID, (SELECT S.SCHEDULE_STATUS FROM pi_schedules S WHERE H.SCHEDULE_ID = S.SCHEDULE_ID AND H.AP_NO = S.AP_NO) AS SCHEDULE_STATUS, H.SCAN_TIME FROM (SELECT T.AP_NO, T.TARGET_ID, L.LOCATION_ID, T.NAME AS FULL_NAME, SUBSTRING_INDEX(T.NAME, '.', 1) AS HOST_NAME, (CASE WHEN L.PROTOCOL = 'onedrive' THEN L.PATH ELSE SUBSTRING_INDEX(SUBSTRING_INDEX(T.NAME, '.', -2), '.', 1) END) AS NAME, SUBSTRING_INDEX(T.NAME, '.', -1) AS SERIAL, T.NET_ID, MAX(CAST(S.SCHEDULE_ID AS INT)) AS SCHEDULE_ID, S.SCHEDULE_STATUS, FROM_UNIXTIME(S.SCHEDULE_NEXT_SCAN, '%Y-%m-%d %H:%i:%s') AS SCAN_TIME FROM pi_ap_server AP, pi_locations L, pi_targets T LEFT OUTER JOIN pi_schedules S ON T.TARGET_ID = S.SCHEDULE_TARGET_ID AND T.AP_NO = S.AP_NO WHERE 1=1
AND T.NET_ID = #{net_id}
AND L.NET_ID = #{net_id}
AND T.AP_NO = AP.AP_NO AND T.TARGET_ID = L.TARGET_ID AND AP.IS_SERVER != 1 GROUP BY T.AP_NO,
L.LOCATION_ID
T.TARGET_ID
) H

