mapper.select:
SELECT ROUND((CASE WHEN (IFNULL(PRE_PATH_CNT,0) = 0 AND IFNULL(PATH_CNT,0) = 0) THEN 0 WHEN (IFNULL(PRE_PATH_CNT,0)= 0 ) THEN 1 ELSE (PATH_CNT - PRE_PATH_CNT) / PRE_PATH_CNT END )*100,2) AS PATH_RATE, ROUND((CASE WHEN (IFNULL(PRE_TOTAL,0) = 0 AND IFNULL(TOTAL,0) = 0) THEN 0 WHEN (IFNULL(PRE_TOTAL,0)= 0 ) THEN 1 ELSE (TOTAL - PRE_TOTAL) / PRE_TOTAL END )*100,2) AS TOTAL_RATE, IFNULL(PATH_CNT,0) AS PATH_CNT, IFNULL(TOTAL,0) AS TOTAL, DATES.DATES FROM (SELECT DISTINCT
DATE_FORMAT(DATE_ADD(LAST_DAY(DATE_ADD(NOW(), INTERVAL -1 YEAR)), INTERVAL seq-1 DAY), '%Y-%m-01') AS DATES FROM seq_1_to_365
DATE_FORMAT(DATE_ADD(LAST_DAY(DATE_ADD(NOW(), INTERVAL -10 YEAR)), INTERVAL seq-1 MONTH), '%Y-%m-01') AS DATES FROM seq_1_to_365 WHERE DATE_FORMAT(DATE_ADD(LAST_DAY(DATE_ADD(NOW(), INTERVAL -10 YEAR)), INTERVAL seq-1 MONTH), '%Y-%m-01') <= DATE_FORMAT(NOW(), '%Y-%m-01')
AND DATE_FORMAT(DATE_ADD(LAST_DAY(DATE_ADD(NOW(), INTERVAL -10 YEAR)), INTERVAL seq-1 MONTH), '%Y-%m') >= #{fromDate} AND DATE_FORMAT(DATE_ADD(LAST_DAY(DATE_ADD(NOW(), INTERVAL -10 YEAR)), INTERVAL seq-1 MONTH), '%Y-%m') <= #{toDate}
) DATES LEFT OUTER JOIN (SELECT OG.* , IFNULL(PG.PATH_CNT, 0) AS PRE_PATH_CNT , IFNULL(PG.TOTAL,0) AS PRE_TOTAL
FROM (SELECT SUM(PATH_CNT) AS PATH_CNT,SUM(TOTAL) AS TOTAL,YM AS CUR_YM, CONCAT(YM,'-01') AS SEARCH_DATE FROM (SELECT PT.TARGET_ID,PT.ap_no,SL.SEARCH_DATE,PT.PATH_CNT,PT.total,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') AS YM ,RANK() OVER (PARTITION BY SL.TARGET_ID, SL.AP_NO,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') ORDER BY SL.SEARCH_DATE DESC) AS RANK FROM (SELECT *,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d') AS SEARCH_DATE FROM pi_scheduled_location GROUP BY TARGET_ID,AP_NO,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d')) SL JOIN pi_total PT ON SL.target_id = PT.TARGET_ID AND SL.AP_NO = PT.AP_NO AND DATE_FORMAT(DATE_SUB(PT.REGDATE, INTERVAL 1 DAY),'%Y-%m-%d') = SL.SEARCH_DATE) PD #WHERE RANK = 1 GROUP BY PD.YM) OG LEFT OUTER JOIN (SELECT SUM(PATH_CNT) AS PATH_CNT,SUM(TOTAL) AS TOTAL,YM AS CUR_YM, CONCAT(YM,'-01') AS SEARCH_DATE FROM (SELECT PT.TARGET_ID,PT.ap_no,SL.SEARCH_DATE,PT.PATH_CNT,PT.total,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') AS YM ,RANK() OVER (PARTITION BY SL.TARGET_ID, SL.AP_NO,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') ORDER BY SL.SEARCH_DATE DESC) AS RANK FROM (SELECT *,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d') AS SEARCH_DATE FROM pi_scheduled_location GROUP BY TARGET_ID,AP_NO,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d')) SL JOIN pi_total PT ON SL.target_id = PT.TARGET_ID AND SL.AP_NO = PT.AP_NO AND DATE_FORMAT(DATE_SUB(PT.REGDATE, INTERVAL 1 DAY),'%Y-%m-%d') = SL.SEARCH_DATE) PD #WHERE RANK = 1 GROUP BY PD.YM ) PG ON DATE_FORMAT(DATE_SUB(OG.SEARCH_DATE, INTERVAL 1 MONTH),'%Y-%m') = PG.CUR_YM) D ON D.SEARCH_DATE = DATES.DATES

SELECT ROUND((CASE WHEN (IFNULL(PRE_PATH_CNT,0) = 0 AND IFNULL(PATH_CNT,0) = 0) THEN 0 WHEN (IFNULL(PRE_PATH_CNT,0)= 0 ) THEN 1 ELSE (PATH_CNT - PRE_PATH_CNT) / PRE_PATH_CNT END )*100,2) AS PATH_RATE, ROUND((CASE WHEN (IFNULL(PRE_TOTAL,0) = 0 AND IFNULL(TOTAL,0) = 0) THEN 0 WHEN (IFNULL(PRE_TOTAL,0)= 0 ) THEN 1 ELSE (TOTAL - PRE_TOTAL) / PRE_TOTAL END )*100,2) AS TOTAL_RATE, IFNULL(PATH_CNT,0) AS PATH_CNT, IFNULL(TOTAL,0) AS TOTAL, T.TARGET_ID, T.AP_NO, T.NAME AS NAME FROM PI_TARGETS T LEFT OUTER JOIN
(SELECT OG.*,IFNULL(PG.PATH_CNT, 0) AS PRE_PATH_CNT , IFNULL(PG.TOTAL,0) AS PRE_TOTAL , RANK() OVER (PARTITION BY OG.TARGET_ID, OG.AP_NO ORDER BY OG.CUR_YM DESC) AS RANK FROM
(SELECT T.NAME,PT.TARGET_ID,PT.ap_no,SL.SEARCH_DATE,SUM(PT.PATH_CNT) AS PATH_CNT,SUM(PT.total) AS TOTAL,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') AS CUR_YM FROM (SELECT *,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d') AS SEARCH_DATE FROM pi_scheduled_location GROUP BY TARGET_ID,AP_NO,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d')) SL JOIN pi_total PT ON SL.target_id = PT.TARGET_ID AND SL.AP_NO = PT.AP_NO AND DATE_FORMAT(DATE_SUB(PT.REGDATE, INTERVAL 1 DAY),'%Y-%m-%d') = SL.SEARCH_DATE JOIN PI_TARGETS T ON PT.TARGET_ID = T.TARGET_ID AND PT.AP_NO = T.AP_NO
WHERE DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') >= #{fromDate} AND DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') <= #{toDate}
GROUP BY T.TARGET_ID, T.AP_NO,CUR_YM) OG LEFT OUTER JOIN (SELECT T.NAME,PT.TARGET_ID,PT.ap_no,SL.SEARCH_DATE,SUM(PT.PATH_CNT) AS PATH_CNT,SUM(PT.total) AS TOTAL,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') AS CUR_YM FROM (SELECT *,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d') AS SEARCH_DATE FROM pi_scheduled_location GROUP BY TARGET_ID,AP_NO,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d')) SL JOIN pi_total PT ON SL.target_id = PT.TARGET_ID AND SL.AP_NO = PT.AP_NO AND DATE_FORMAT(DATE_SUB(PT.REGDATE, INTERVAL 1 DAY),'%Y-%m-%d') = SL.SEARCH_DATE JOIN PI_TARGETS T ON PT.TARGET_ID = T.TARGET_ID AND PT.AP_NO = T.AP_NO GROUP BY T.TARGET_ID, T.AP_NO,CUR_YM) PG ON DATE_FORMAT(DATE_SUB(OG.SEARCH_DATE, INTERVAL 1 MONTH),'%Y-%m') = PG.CUR_YM AND OG.TARGET_ID = PG.TARGET_ID AND OG.AP_NO = PG.AP_NO) D ON D.TARGET_ID = T.TARGET_ID AND D.AP_NO = T.AP_NO AND D.RANK = 1 WHERE 1=1
AND T.TARGET_ID IN (
#{item}
)
AND D.TARGET_ID IS NOT NULL

SELECT ROUND((CASE WHEN (IFNULL(PRE_PATH_CNT,0) = 0 AND IFNULL(PATH_CNT,0) = 0) THEN 0 WHEN (IFNULL(PRE_PATH_CNT,0)= 0 ) THEN 1 ELSE (PATH_CNT - PRE_PATH_CNT) / PRE_PATH_CNT END )*100,2) AS PATH_RATE, ROUND((CASE WHEN (IFNULL(PRE_TOTAL,0) = 0 AND IFNULL(TOTAL,0) = 0) THEN 0 WHEN (IFNULL(PRE_TOTAL,0)= 0 ) THEN 1 ELSE (TOTAL - PRE_TOTAL) / PRE_TOTAL END )*100,2) AS TOTAL_RATE, PATH_CNT, TOTAL, G.NAME AS GROUP_NAME FROM ( SELECT NAME,UP_IDX,IDX FROM pi_target_group WHERE TYPE=0 UNION ALL SELECT '미그룹' AS NAME , -1 AS UP_IDX, -1 AS IDX
) G LEFT OUTER JOIN (SELECT TGS.NAME AS GROUP_NAME,OG.* , IFNULL(PG.PATH_CNT, 0) AS PRE_PATH_CNT , IFNULL(PG.TOTAL,0) AS PRE_TOTAL , RANK() OVER (PARTITION BY UP_IDX ORDER BY OG.CUR_YM DESC) AS RANK FROM (SELECT TG.NAME,IFNULL(TG.UP_IDX,-1) AS UP_IDX,PT.TARGET_ID,PT.ap_no,SL.SEARCH_DATE,PT.PATH_CNT,PT.total,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') AS CUR_YM FROM (SELECT *,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d') AS SEARCH_DATE FROM pi_scheduled_location GROUP BY TARGET_ID,AP_NO,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d')) SL JOIN pi_total PT ON SL.target_id = PT.TARGET_ID AND SL.AP_NO = PT.AP_NO AND DATE_FORMAT(DATE_SUB(PT.REGDATE, INTERVAL 1 DAY),'%Y-%m-%d') = SL.SEARCH_DATE LEFT OUTER JOIN pi_target_group TG ON PT.TARGET_ID = TG.TARGET_ID AND PT.AP_NO = TG.AP_NO
WHERE DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') >= #{fromDate} AND DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') <= #{toDate}
GROUP BY TG.UP_IDX,CUR_YM) OG LEFT OUTER JOIN pi_target_group TGS ON TGS.IDX = OG.UP_IDX LEFT OUTER JOIN (SELECT TG.UP_IDX,PT.TARGET_ID,PT.ap_no,SL.SEARCH_DATE,PT.PATH_CNT,PT.total,DATE_FORMAT(SL.SEARCH_DATE, '%Y-%m') AS CUR_YM FROM (SELECT *,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d') AS SEARCH_DATE FROM pi_scheduled_location GROUP BY TARGET_ID,AP_NO,DATE_FORMAT(FROM_UNIXTIME(updated), '%Y-%m-%d')) SL JOIN pi_total PT ON SL.target_id = PT.TARGET_ID AND SL.AP_NO = PT.AP_NO AND DATE_FORMAT(DATE_SUB(PT.REGDATE, INTERVAL 1 DAY),'%Y-%m-%d') = SL.SEARCH_DATE LEFT OUTER JOIN pi_target_group TG ON PT.TARGET_ID = TG.TARGET_ID AND PT.AP_NO = TG.AP_NO GROUP BY TG.UP_IDX,CUR_YM) PG ON DATE_FORMAT(DATE_SUB(OG.SEARCH_DATE, INTERVAL 1 MONTH),'%Y-%m') = PG.CUR_YM AND OG.UP_IDX = PG.UP_IDX) D ON D.UP_IDX = G.IDX AND RANK = 1
